4600     bool IsEquality =
4601         (CmpVal->isZero() || CmpVal->isOne()) && ICmpInst::isEquality(Pred);
4602     // Case c
4603     bool IsPositive = CmpVal->isAllOnes() && Pred == ICmpInst::ICMP_SGT;
4604     // Cases b, d, and f
4605     bool IsNegative = (CmpVal->isZero() || CmpVal->isOne() || *CmpVal == 2) &&
4606                       Pred == ICmpInst::ICMP_SLT;
4607     return IsEquality || IsPositive || IsNegative;
4608   };
4609 
4610   const auto IsValidAndUminCmp = [&]() {
4611     const auto LeadingOnes = CmpVal->countl_one();
4612 
4613     // Cases g and k
4614     bool IsEquality =
4615         (CmpVal->isAllOnes() || LeadingOnes + 1 == CmpVal->getBitWidth()) &&
4616         ICmpInst::isEquality(Pred);
4617     // Case h
4618     bool IsNegative = CmpVal->isZero() && Pred == ICmpInst::ICMP_SLT;
4619     // Cases i, j, and l
4620     bool IsPositive =
4621         // if the number has at least N - 2 leading ones
4622         // and the two LSBs are:
4623         //   - 1 x 1 -> -1
4624         //   - 1 x 0 -> -2
4625         //   - 0 x 1 -> -3
4626         LeadingOnes + 2 >= CmpVal->getBitWidth() &&
4627         ((*CmpVal)[0] || (*CmpVal)[1]) && Pred == ICmpInst::ICMP_SGT;
